  (387, 'GSS I', 5, 326, 65, 'Renta Mixta', 'Argentina', 'Corto Plazo', NULL, 1, '2006-03-06', 1, '517', 'Es un fondo que tiene como objetivo invertir y administrar una cartera de activos financieros de corto plazo y riesgo bajo, a fin de obtener un rendimiento estable acorde con las características de los activos que componen su patrimonio.', 1),
  (388, 'GSS II', 5, 326, 65, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2006-03-06', 1, '518', 'El objetivo del fondo es invertir y administrar una cartera de activos financieros de mediano plazo y riesgo medio, a fin de obtener un rendimiento moderado acorde con las características de los activos que componen su patrimonio.', 1),
  (389, 'GSS III', 5, 326, 65, 'Renta Mixta', 'Argentina', 'Largo Plazo', NULL, 1, '2006-03-06', 1, '519', 'Este fondo propone invertir y administrar una cartera de activos financieros principalmente de largo plazo y riesgo potencialmente alto, a fin de obtener un rendimiento acorde con las características de los activos que componen su patrimonio.', 2),
