  (1201, 'MAF Mix II', 5, 371, 436, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 2, '2020-05-05', 1, '1087', 'Sin datos', 2),
  (503, 'MAF Money Market', 4, 371, 436, 'Plazo Fijo', 'Argentina', 'Corto Plazo', NULL, 1, '2011-09-07', 1, '637', 'Maximizar su valor mediante la creación de una cartera diversificada de depósitos a plazo y cuentas corrientes (Money Market Puro). De esta manera, el fondo busca optimizar la liquidez de los inversores, conservando el capital suscripto, a través del más alto estándar de calidad en inversiones de fondeo.', 0),
  (504, 'MAF Pesos Plus', 3, 371, 436, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2011-09-12', 1, '636', 'Lograr un rendimiento similar a la tasa BADLAR Bancos Privados combinando un alto nivel de liquidez con una alta calidad crediticia de sus activos. El fondo está constituido por una cartera diversificada de instrumentos de renta fija de corto plazo.', 1),
  (497, 'MAF Renta', 3, 371, 436, 'Renta Fija', 'Argentina', 'Largo Plazo', NULL, 1, '2011-08-03', 1, '633', 'Maximizar su valor mediante la inversión en una cartera diversificada de bonos soberanos, provinciales y corporativos de Argentina. Este vehículo permitirá a los inversores sofisticados mejorar la diversificación de su cartera y reducir los costos de transacción proveyendo mayor liquidez.', 2),
  (554, 'MAF Renta Argentina', 3, 371, 436, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 1, '2013-02-28', 1, '692', 'Maximizar su valor mediante la inversión en una cartera diversificada de instrumentos que ajusten en base a la evolución del tipo de cambio oficial. Este vehículo proporcionará a los inversores la posibilidad de una mayor diversificación de sus carteras y, al mismo tiempo, reducir los costos de transacción proveyendo mayor liquidez.', 2),
  (506, 'MAF Renta Argentina 2', 3, 371, 436, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 1, '2011-09-14', 1, '634', 'Maximizar su valor mediante la inversión en una cartera diversificada de bonos corporativos de Argentina, en su mayoría denominados en dólares. El fondo proporciona a los inversores sofisticados un aumento en la diversificación de su cartera y, al mismo tiempo, permite reducir los costos de transacción y provee de una mayor liquidez.', 3),
  (584, 'MAF Renta Balanceada', 5, 371, 436, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2014-02-14', 1, '725', 'Ofrecer al cliente una cartera diversificada de letras y bonos provinciales, con un mix de activos en función de nuestro view de tasas de interés y tipo de cambio, con un adecuado nivel de riesgo crediticio', 2),
  (548, 'MAF Renta Balanceada 2', 5, 371, 436, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2012-12-10', 1, '680', NULL, 2),
  (546, 'MAF Renta Fija Cobertura', 3, 371, 436, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 1, '2012-12-10', 1, '682', 'Asegurar una cobertura al tipo de cambio oficial dólar/peso.', 2),
  (576, 'MAF Renta Mixta', 5, 371, 436, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2013-12-05', 1, '719', NULL, 2),
  (1358, 'Max Abierto PyMEs', 6, 3014, 115, 'Renta Mixta', 'Global', 'Flexible', NULL, 1, '2022-09-08', 1, '1285', 'El objetivo del Fondos es obtener la apreciación del valor del patrimonio mediante ingresos corrientes y ganancias de capital por la compra y venta de valores negociables, instrumentos financieros y otros activos financieros de renta fija o variable, de carácter público o privado, nacionales o extranjeros.', 2),
  (1614, 'Max Acciones Argentinas', 2, 3014, 115, 'Renta Variable', 'Argentina', 'Largo Plazo', NULL, 1, '2025-01-30', 1, '1619', 'Max Acciones Argentinas invierte en acciones de compañías argentinas, buscando lograr rentabilidades superiores a su índice de referencia, el S&P Merval. El Fondo es de gestión activa, basado en el análisis fundamental a través del estudio de variables críticas de los modelos de negocios de las compañías.', 1),
